import openpyxl
import re
from itertools import product

wb = openpyxl.load_workbook('input.xlsx')
ws_in = wb['Input']
ws_out = wb['Output']

# Clear output sheet
for row in ws_out.iter_rows(min_row=1, max_row=ws_out.max_row, max_col=ws_out.max_column):
    for cell in row:
        cell.value = None

# Header
headers = ['wtype_id', 'name', 'status', 'orgId', 'careType', 'specialtyId', 'contextId']
for i, h in enumerate(headers, 1):
    ws_out.cell(row=1, column=i, value=h)

output_cols = ['orgId', 'careType', 'specialtyId', 'contextId']

def parse_filter(f):
    """Parse filter string into dict of key -> list of values"""
    result = {}
    # Match patterns like ("key" = "value") and ("key" IN LIST val1,val2)
    for match in re.finditer(r'\("(\w+)"\s*=\s*"([^"]+)"\)', f):
        result[match.group(1)] = [match.group(2)]
    for match in re.finditer(r'\("(\w+)"\s+IN\s+LIST\s+([^)]+)\)', f):
        vals = [v.strip() for v in match.group(2).rstrip(';').split(',')]
        result[match.group(1)] = vals
    return result

out_row = 2
for row in ws_in.iter_rows(min_row=2, max_row=ws_in.max_row, values_only=True):
    wtype_id, name, status, filter_str = row
    parsed = parse_filter(filter_str)

    # Get lists for each output column
    col_values = []
    for col in output_cols:
        if col in parsed:
            col_values.append(parsed[col])
        else:
            col_values.append([None])

    # Cross product
    for combo in product(*col_values):
        ws_out.cell(row=out_row, column=1, value=wtype_id)
        ws_out.cell(row=out_row, column=2, value=name)
        ws_out.cell(row=out_row, column=3, value=status)
        for i, val in enumerate(combo):
            if val is not None:
                # Try to convert to int (omit leading zeros)
                try:
                    val = int(val)
                except ValueError:
                    pass
            ws_out.cell(row=out_row, column=4+i, value=val)
        out_row += 1

wb.save('output.xlsx')
print(f"Written {out_row - 2} data rows")

# Verify
wb2 = openpyxl.load_workbook('output.xlsx')
for sheet_name in wb2.sheetnames:
    ws = wb2[sheet_name]
    print(f"\n--- {sheet_name} ---")
    for row in ws.iter_rows(min_row=1, max_row=ws.max_row, max_col=ws.max_column, values_only=True):
        if any(v is not None for v in row):
            print(list(row))
